def get_conn(self, headers=None):
    """
    Create and configure a requests Session from Airflow connection details.

    If an HTTP connection ID is provided, this method loads the corresponding Connection
    and configures the session accordingly:
      - base_url is built from the host (and optional port). If host already contains a scheme,
        that scheme is used; otherwise the default is http or conn.schema.
      - If login/password are provided, session.auth is set.
      - If extra is provided (as JSON or dict), it is merged into session.headers.
    Any additional headers passed via the `headers` argument are merged into the session headers.

    Returns:
      requests.Session: The configured session.
    """
    session = requests.Session()
    if self.http_conn_id:
        conn = self.get_connection(self.http_conn_id)

        if "://" in conn.host:
            self.base_url = conn.host
        else:
            schema = conn.schema if conn.schema else "http"
            self.base_url = f"{schema}://{conn.host}"

        if conn.port:
            self.base_url = f"{self.base_url}:{conn.port}"
        if conn.login:
            session.auth = (conn.login, conn.password)
        if conn.extra:
            try:
                session.headers.update(conn.extra_dejson)
            except (TypeError, ValueError):
                self.log.warning('Connection to %s has invalid extra field.', conn.host)
    if headers:
        session.headers.update(headers)

    return session
